{
    float2 uv0 = uv;
    float2 uv1 = uv + 0.05 * sin(uv.x * 20.0 + _Time.y);

    // sample two textures at slightly different UVs
    sampler2D tex0 : register(s0);
    sampler2D tex1 : register(s1);

    float4 col0 = tex2D(tex0, uv0);
    float4 col1 = tex2D(tex1, uv1);

    // blend between the two colors based on time
    float4 result = lerp(col0, col1, frac(_Time.y));

    return result;
}
